sub load_plugin_config {
    my ($config_file) = @_;
    my $plugin_code = '';
    
    open my $fh, '<', $config_file or die "Cannot open $config_file: $!";
    while (my $line = <$fh>) {
        $plugin_code .= $line;
    }
    close $fh;
    
    return $plugin_code;
}

sub register_plugin {
    my ($name, $code) = @_;
    $plugin_registry->{$name} = $code;
}

sub execute_plugin {
    my ($name, @args) = @_;
    
